#!/usr/bin/env pwsh
# Test harness: drives every test case through the GitHub Actions workflow via
# `act`. For each case we copy the project to a temp directory, init a git repo,
# run `act push` with the fixture overridden via --env CONFIG_PATH, capture the
# output, and assert exact expected values against the matrix the workflow
# emits between the MATRIX_JSON_BEGIN/END markers.
[CmdletBinding()]
param(
    [string] $ResultPath = (Join-Path (Get-Location) 'act-result.txt')
)

$ErrorActionPreference = 'Stop'
Set-StrictMode -Version 3.0

$here = Split-Path -Parent $MyInvocation.MyCommand.Path
Push-Location $here
try {

# Test cases: each runs the workflow with a fixture and asserts on the
# expected matrix shape. We assert exact values, not just "something appeared".
$cases = @(
    @{
        Name = 'basic'
        ConfigPath = 'fixtures/basic.json'
        ExpectedIncludeCount = 4
        ExpectedFailFast = $true
        ExpectedMaxParallel = 4
        # Expected entries in the matrix.include array, order-insensitive.
        ExpectedEntries = @(
            @{ os = 'ubuntu-latest'; node = '18' },
            @{ os = 'ubuntu-latest'; node = '20' },
            @{ os = 'windows-latest'; node = '20' },
            @{ os = 'macos-latest'; node = '20'; experimental = $true }
        )
    },
    @{
        Name = 'single-axis'
        ConfigPath = 'fixtures/single-axis.json'
        ExpectedIncludeCount = 3
        ExpectedFailFast = $false
        ExpectedMaxParallel = $null
        ExpectedEntries = @(
            @{ os = 'ubuntu-latest' },
            @{ os = 'macos-latest' },
            @{ os = 'windows-latest' }
        )
    },
    @{
        Name = 'three-axes-with-exclude'
        ConfigPath = 'fixtures/three-axes.json'
        ExpectedIncludeCount = 6
        ExpectedFailFast = $true
        ExpectedMaxParallel = 6
        ExpectedEntries = @(
            @{ os = 'ubuntu-latest';  python = '3.10'; feature = 'a' },
            @{ os = 'ubuntu-latest';  python = '3.10'; feature = 'b' },
            @{ os = 'ubuntu-latest';  python = '3.11'; feature = 'a' },
            @{ os = 'ubuntu-latest';  python = '3.11'; feature = 'b' },
            @{ os = 'windows-latest'; python = '3.10'; feature = 'a' },
            @{ os = 'windows-latest'; python = '3.11'; feature = 'a' }
        )
    }
)

# Reset result file.
Set-Content -LiteralPath $ResultPath -Value "" -Encoding UTF8

function Test-MatrixContains {
    param([object[]] $Actual, [hashtable] $Expected)
    foreach ($a in $Actual) {
        $match = $true
        foreach ($k in $Expected.Keys) {
            $av = $a.PSObject.Properties[$k]
            if ($null -eq $av) { $match = $false; break }
            if ($av.Value -ne $Expected[$k]) { $match = $false; break }
        }
        # Also check no unexpected keys (strict equality on key set).
        if ($match) {
            $aKeys = @($a.PSObject.Properties.Name | Sort-Object)
            $eKeys = @($Expected.Keys | Sort-Object)
            if ($aKeys.Count -ne $eKeys.Count) { $match = $false }
            else {
                for ($i = 0; $i -lt $aKeys.Count; $i++) {
                    if ($aKeys[$i] -ne $eKeys[$i]) { $match = $false; break }
                }
            }
        }
        if ($match) { return $true }
    }
    return $false
}

$failed = 0
foreach ($case in $cases) {
    $name = $case.Name
    Write-Host "=== Running act for case: $name ===" -ForegroundColor Cyan

    Add-Content -LiteralPath $ResultPath -Value "================================================================"
    Add-Content -LiteralPath $ResultPath -Value "TEST CASE: $name"
    Add-Content -LiteralPath $ResultPath -Value "Config: $($case.ConfigPath)"
    Add-Content -LiteralPath $ResultPath -Value "================================================================"

    $logFile = Join-Path $env:RUNNER_TEMP_DIR_FALLBACK ([System.IO.Path]::GetTempFileName())
    $tmp = New-TemporaryFile; Remove-Item $tmp.FullName -Force
    $logFile = "$($tmp.FullName).log"

    $actArgs = @(
        'push',
        '--rm',
        '--env', "CONFIG_PATH=$($case.ConfigPath)"
    )

    & act @actArgs 2>&1 | Tee-Object -FilePath $logFile | Out-Host
    $actExit = $LASTEXITCODE

    $output = Get-Content -LiteralPath $logFile -Raw
    Add-Content -LiteralPath $ResultPath -Value $output

    Remove-Item $logFile -Force -ErrorAction SilentlyContinue

    Write-Host "act exit code: $actExit"
    if ($actExit -ne 0) {
        Write-Host "FAIL [$name]: act exited with $actExit" -ForegroundColor Red
        $failed++
        continue
    }

    if ($output -notmatch '(?m)Job succeeded') {
        Write-Host "FAIL [$name]: 'Job succeeded' not found" -ForegroundColor Red
        $failed++
        continue
    }

    # Extract matrix JSON between markers.
    $m = [regex]::Match($output, 'MATRIX_JSON_BEGIN\s*\r?\n(?:\|\s*)?(.+?)\r?\n.*?MATRIX_JSON_END', 'Singleline')
    if (-not $m.Success) {
        Write-Host "FAIL [$name]: matrix markers not found in output" -ForegroundColor Red
        $failed++
        continue
    }
    $jsonRaw = $m.Groups[1].Value.Trim()
    # act prefixes lines with "[Job] | " style markers; strip everything before the first '{'.
    $idx = $jsonRaw.IndexOf('{')
    if ($idx -lt 0) {
        Write-Host "FAIL [$name]: no JSON object in captured matrix line" -ForegroundColor Red
        $failed++
        continue
    }
    $jsonRaw = $jsonRaw.Substring($idx)
    # Ensure we stop at the matching closing brace + any trailing chars.
    try {
        $obj = $jsonRaw | ConvertFrom-Json
    } catch {
        Write-Host "FAIL [$name]: JSON parse error: $($_.Exception.Message)" -ForegroundColor Red
        Write-Host "Raw: $jsonRaw"
        $failed++
        continue
    }

    # Assert exact include count.
    $actualCount = @($obj.matrix.include).Count
    if ($actualCount -ne $case.ExpectedIncludeCount) {
        Write-Host "FAIL [$name]: expected $($case.ExpectedIncludeCount) entries, got $actualCount" -ForegroundColor Red
        $failed++
        continue
    }

    # Assert fail-fast value.
    if ($obj.'fail-fast' -ne $case.ExpectedFailFast) {
        Write-Host "FAIL [$name]: expected fail-fast=$($case.ExpectedFailFast), got $($obj.'fail-fast')" -ForegroundColor Red
        $failed++
        continue
    }

    # Assert max-parallel value (or absence).
    $hasMP = $obj.PSObject.Properties.Name -contains 'max-parallel'
    if ($null -eq $case.ExpectedMaxParallel) {
        if ($hasMP) {
            Write-Host "FAIL [$name]: expected no max-parallel, got $($obj.'max-parallel')" -ForegroundColor Red
            $failed++; continue
        }
    } else {
        if (-not $hasMP -or $obj.'max-parallel' -ne $case.ExpectedMaxParallel) {
            Write-Host "FAIL [$name]: expected max-parallel=$($case.ExpectedMaxParallel), got $($obj.'max-parallel')" -ForegroundColor Red
            $failed++; continue
        }
    }

    # Assert each expected entry is present.
    $allFound = $true
    foreach ($expected in $case.ExpectedEntries) {
        if (-not (Test-MatrixContains -Actual @($obj.matrix.include) -Expected $expected)) {
            Write-Host "FAIL [$name]: missing expected entry: $($expected | ConvertTo-Json -Compress)" -ForegroundColor Red
            $allFound = $false
        }
    }
    if (-not $allFound) { $failed++; continue }

    Write-Host "PASS [$name]" -ForegroundColor Green
    Add-Content -LiteralPath $ResultPath -Value "RESULT: PASS"
    Add-Content -LiteralPath $ResultPath -Value ""
}

if ($failed -gt 0) {
    Write-Host "`n$failed case(s) failed" -ForegroundColor Red
    exit 1
}
Write-Host "`nAll $($cases.Count) act cases passed" -ForegroundColor Green

} finally {
    Pop-Location
}

